const a = [
  {"id":1692,"text":"Which of the following will not be a clinical finding in chronic obstructive pulmonary disease (COPD)?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 91.","responses":[{"text":"Cough with sputum","correct":false,"visible":false},{"text":"Breathing through pursed lips","correct":false,"visible":false},{"text":"Wheezing","correct":false,"visible":false},{"text":"Splenomegaly","correct":true,"visible":false},{"text":"Weight loss","correct":false,"visible":false}]},{"id":1694,"text":"Which of the following features, according to Light's criteria, is suggestive of exudative effusion?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 564.","responses":[{"text":"Pleural fluid LDH : serum LDH ratio \u003e 0.6","correct":true,"visible":false},{"text":"Protein content of fluid \u003c 30 g/L","correct":false,"visible":false},{"text":"Pleural fluid LDH \u003c 2/3 of upper limit of normal serum LDH","correct":false,"visible":false},{"text":"Pleural fluid protein : serum protein ratio \u003c 0.5","correct":false,"visible":false},{"text":"Pleural fluid glucose is higher than serum glucose","correct":false,"visible":false}]},{"id":1730,"text":"Which of the following is true about adipocere?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 151.","responses":[{"text":"Adipoceres always have a hard and cracked appearance","correct":false,"visible":false},{"text":"Caused by hydrolysis and hydrogenation","correct":true,"visible":false},{"text":"Cold temperature favors adipocere formation","correct":false,"visible":false},{"text":"Anaerobic conditions inhibit adipocere","correct":false,"visible":false},{"text":"Highly acidic soil prevents adipocere formation","correct":false,"visible":false}]},{"id":1731,"text":"Which of these is not a feature seen in the eyes after death?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 137, 138.","responses":[{"text":"Flaccidity of the eyeball","correct":false,"visible":false},{"text":"Gradual decline in vitreal potassium levels","correct":true,"visible":false},{"text":"Cattle trucking of retinal vessels","correct":false,"visible":false},{"text":"Taches noires on the sclera","correct":false,"visible":false},{"text":"Opacity of the cornea","correct":false,"visible":false}]},{"id":1732,"text":"Which of the following tuberculosis drugs causes vestibular toxicity?","explanation":null,"reference":"1) Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 194.\r\n\r\n2) Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 847.","responses":[{"text":"Azithromycin","correct":false,"visible":false},{"text":"Streptomycin","correct":true,"visible":false},{"text":"Erythromycin","correct":false,"visible":false},{"text":"Vancomycin","correct":false,"visible":false},{"text":"Isoniazid","correct":false,"visible":false}]},{"id":1733,"text":"Which of the following is a second-line tuberculosis drug?","explanation":null,"reference":"Katzung BG, Kruidering-Hall M, Trevor AJ. Katzung \u0026 Trevor’s Pharmacology Examination \u0026 Board Review. 12th ed. McGraw-Hill Education; 2019: 403.","responses":[{"text":"Pyrazinamide","correct":false,"visible":false},{"text":"Streptokinase","correct":false,"visible":false},{"text":"Ethionamide","correct":true,"visible":false},{"text":"Ethambutol","correct":false,"visible":false},{"text":"Isoniazid","correct":false,"visible":false}]},{"id":1734,"text":"If a person stands behind a thin cotton curtain, which radiation will he be protected from?","explanation":null,"reference":"11. 6: penetrating power of radiation. Chemistry LibreTexts. Published September 24, 2021. Accessed May 16, 2022. https://chem.libretexts.org/Courses/Sacramento_City_College/SCC%3A_CHEM_330_-_Adventures_in_Chemistry_(Alviar-Agnew)/11%3A_Nuclear_Chemistry/11.06%3A_Penetrating_Power_of_Radiation","responses":[{"text":"Neutron","correct":false,"visible":false},{"text":"X-Ray","correct":false,"visible":false},{"text":"Beta","correct":false,"visible":false},{"text":"Gamma","correct":false,"visible":false},{"text":"Alpha","correct":true,"visible":false}]},{"id":1735,"text":"What is the optimum temperature range for putrefaction?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 149.","responses":[{"text":"60 °F and 100 °F","correct":false,"visible":false},{"text":"50 °F and 100 °F","correct":false,"visible":false},{"text":"80 °F and 90 °F","correct":false,"visible":false},{"text":"70 °F and 110 °F","correct":false,"visible":false},{"text":"70 °F and 100 °F","correct":true,"visible":false}]},{"id":1736,"text":"What is nosocomial pneumonia also known as?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 702.","responses":[{"text":"Atypical pneumonia","correct":false,"visible":false},{"text":"Interstitial pneumonia","correct":false,"visible":false},{"text":"Lobar pneumonia","correct":false,"visible":false},{"text":"Bronchopneumonia","correct":false,"visible":false},{"text":"Hospital acquired pneumonia","correct":true,"visible":false}]},{"id":1737,"text":"What is the most common cause of community-acquired pneumonia?","explanation":"The most common cause of community-acquired pneumonia is ***Streptococcus pneumoniae***. Streptococcus pneumoniae is a gram-positive bacterium that colonizes the upper respiratory tract and can cause infection when it enters the lower respiratory tract.\r\n\r\nOther pathogens such as *Mycoplasma pneumoniae, Legionella pneumophila, Klebsiella pneumoniae*, and *Staphylococcus aureus* can also cause community-acquired pneumonia, but Streptococcus pneumoniae is the most common causative agent.","reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 88.","responses":[{"text":"Legionella pneumophilia","correct":false,"visible":false},{"text":"Klebsiella pneumoniae","correct":false,"visible":false},{"text":"Staphylococcus aureus","correct":false,"visible":false},{"text":"Streptococcus pneumoniae","correct":true,"visible":false},{"text":"Mycoplasma pneumoniae","correct":false,"visible":false}]},{"id":1738,"text":"Which of the following is the first to undergo putrefaction after death?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 148.","responses":[{"text":"Heart","correct":false,"visible":false},{"text":"Bladder","correct":false,"visible":false},{"text":"Spleen","correct":true,"visible":false},{"text":"Lungs","correct":false,"visible":false},{"text":"Kidneys","correct":false,"visible":false}]},{"id":1739,"text":"In which of the following diseases does the total lung capacity decrease?","explanation":null,"reference":"Le T, Vikas Bhushan. First Aid for the USMLE Step 1 2021. 31st ed. McGraw-Hill Education; 2021: 699.","responses":[{"text":"Chronic bronchitis","correct":false,"visible":false},{"text":"Asthma","correct":false,"visible":false},{"text":"Pneumoconiosis","correct":true,"visible":false},{"text":"Emphysema","correct":false,"visible":false},{"text":"Bronchiectasis","correct":false,"visible":false}]},{"id":1740,"text":"What does Casper's dictum mean?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 150.","responses":[{"text":"Degree of mutilation","correct":false,"visible":false},{"text":"Cause of death","correct":false,"visible":false},{"text":"Rate of putrefaction","correct":true,"visible":false},{"text":"Time of death","correct":false,"visible":false},{"text":"Cause of putrefaction","correct":false,"visible":false}]},{"id":1741,"text":"Curschmann spirals are a classical histopathological finding of which disease?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 91.","responses":[{"text":"Bronchitis","correct":false,"visible":false},{"text":"Asthma","correct":true,"visible":false},{"text":"Emphysema","correct":false,"visible":false},{"text":"Pneumonia","correct":false,"visible":false},{"text":"Bronchiectasis","correct":false,"visible":false}]},{"id":1742,"text":"What are Charcot-Leyden crystals composed of?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 91.","responses":[{"text":"Silica fibers","correct":false,"visible":false},{"text":"Eosinophil proteins","correct":true,"visible":false},{"text":"Aggregates of calcium and protein","correct":false,"visible":false},{"text":"Uric acid","correct":false,"visible":false},{"text":"Lysozyme","correct":false,"visible":false}]},{"id":1743,"text":"A 30-year-old female receiving anti-tuberculosis drugs complains of disturbance in vision and loss of visual acuity. Which of the following drugs would have caused this?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 194.","responses":[{"text":"Isoniazid","correct":false,"visible":false},{"text":"Rifampin","correct":false,"visible":false},{"text":"Cycloserine","correct":false,"visible":false},{"text":"Pyrazinamide","correct":false,"visible":false},{"text":"Ethambutol","correct":true,"visible":false}]},{"id":1745,"text":"A dead body is discovered lying hidden amongst bushes in a supine position, with postmortem lividity fully established, and black in color. In the given scenario, which area of the body will not demonstrate the postmortem lividity?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 140.","responses":[{"text":"Hands","correct":false,"visible":false},{"text":"Sacral region","correct":false,"visible":false},{"text":"Back of ears","correct":false,"visible":false},{"text":"Neck","correct":false,"visible":false},{"text":"Occipital scalp","correct":true,"visible":false}]},{"id":1746,"text":"What is the mechanism of action of methylxanthines?","explanation":null,"reference":"Katzung BG, Kruidering-Hall M, Trevor AJ. Katzung \u0026 Trevor’s Pharmacology Examination \u0026 Board Review. 12th ed. McGraw-Hill Education; 2019: 175.","responses":[{"text":"Activation of adenosine receptors","correct":false,"visible":false},{"text":"Decrease in cAMP","correct":false,"visible":false},{"text":"None of these","correct":true,"visible":false},{"text":"Activation of phosphodiesterase","correct":false,"visible":false},{"text":"Decrease in cGMP","correct":false,"visible":false}]},{"id":1747,"text":"What is acid rain caused by?","explanation":null,"reference":"Acid rain | definition, causes, effects, \u0026 formulas | britannica. Accessed May 16, 2022. https://www.britannica.com/science/acid-rain","responses":[{"text":"Global warming","correct":false,"visible":false},{"text":"Increased carbon dioxide","correct":false,"visible":false},{"text":"Increased sulfur dioxide","correct":true,"visible":false},{"text":"Cow dung","correct":false,"visible":false},{"text":"Coal","correct":false,"visible":false}]},{"id":1748,"text":"A false negative purified protein derivative (PPD) test is NOT found in which of the following?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 594.","responses":[{"text":"In newborns","correct":false,"visible":false},{"text":"Prior Bacille Calmette-Guérin (BCG) vaccination","correct":true,"visible":false},{"text":"In Human Immunodeficiency Virus (HIV) positive tests","correct":false,"visible":false},{"text":"In malignancy","correct":false,"visible":false},{"text":"In malnutrition","correct":false,"visible":false}]},{"id":1749,"text":"Which of the following is incorrect about smokers' macrophages?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n695, 696.","responses":[{"text":"Finely granular iron may be seen in cytoplasm","correct":false,"visible":false},{"text":"Feature of desquamative interstitial pneumonia","correct":false,"visible":false},{"text":"Dusty brown pigment in macrophages","correct":false,"visible":false},{"text":"Presenting symptom is dyspnea and productive cough","correct":true,"visible":false},{"text":"Surfactant found in phagocytic vacuoles","correct":false,"visible":false}]},{"id":1750,"text":"What kind of emphysema occurs in coal workers pneumoconiosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n689.","responses":[{"text":"Interstitial","correct":false,"visible":false},{"text":"Paraseptal","correct":false,"visible":false},{"text":"Panacinar","correct":false,"visible":false},{"text":"Centriacinar","correct":true,"visible":false},{"text":"Diffuse","correct":false,"visible":false}]},{"id":1757,"text":"Which of the following is the narrowest part of the pediatric airway?","explanation":null,"reference":"Vijayasekaran S. Pediatric airway pathology. Frontiers in Pediatrics. 2020;8. Accessed May 17, 2022. https://www.frontiersin.org/article/10.3389/fped.2020.00246","responses":[{"text":"Larynx","correct":false,"visible":false},{"text":"Trachea","correct":false,"visible":false},{"text":"Subglottic area","correct":false,"visible":false},{"text":"Cricoid ring","correct":true,"visible":false},{"text":"Glottis","correct":false,"visible":false}]},{"id":1758,"text":"What is the most common site of lung cancer metastasis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n717.","responses":[{"text":"Hilar lymph nodes","correct":true,"visible":false},{"text":"Liver","correct":false,"visible":false},{"text":"Adrenals","correct":false,"visible":false},{"text":"Bone","correct":false,"visible":false},{"text":"Brain","correct":false,"visible":false}]},{"id":1759,"text":"Which of the following is the most common occupational lung disease?","explanation":null,"reference":"(1) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 692.\r\n\r\n(2) Silicosis - an overview | sciencedirect topics. Accessed April 22, 2022. https://www.sciencedirect.com/topics/medicine-and-dentistry/silicosis","responses":[{"text":"Progressive massive fibrosis","correct":false,"visible":false},{"text":"Silicosis","correct":true,"visible":false},{"text":"Asymptomatic anthracosis","correct":false,"visible":false},{"text":"Asbestosis","correct":false,"visible":false},{"text":"Farmer's lung","correct":false,"visible":false}]},{"id":1760,"text":"Which type of hypersensitivity is being displayed in a positive Mantoux test?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n371.","responses":[{"text":"Type III","correct":false,"visible":false},{"text":"Type IV","correct":true,"visible":false},{"text":"Type II","correct":false,"visible":false},{"text":"Type I","correct":false,"visible":false},{"text":"Type VI","correct":false,"visible":false}]},{"id":1761,"text":"Which of the following anti-tuberculosis drugs causes ototoxicity?","explanation":null,"reference":"Katzung BG, Kruidering-Hall M, Trevor AJ. Katzung \u0026 Trevor’s Pharmacology Examination \u0026 Board Review. 12th ed. McGraw-Hill Education; 2019: 386.","responses":[{"text":"Pyrazinamide","correct":false,"visible":false},{"text":"Ethambutol","correct":false,"visible":false},{"text":"Rifampicin","correct":false,"visible":false},{"text":"Isoniazid","correct":false,"visible":false},{"text":"Streptomycin","correct":true,"visible":false}]},{"id":1762,"text":"Which of the following are avoided during chronic obstructive pulmonary disease (COPD)?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 576, 577.","responses":[{"text":"Long-acting beta-agonists","correct":false,"visible":false},{"text":"Anticholinergics","correct":false,"visible":false},{"text":"Inhaled corticosteroids","correct":false,"visible":false},{"text":"Non-steroidal anti-inflammatory drugs","correct":true,"visible":false},{"text":"Short-acting beta-agonists","correct":false,"visible":false}]},{"id":1764,"text":"Which of the following is the most common cancer that can metastasize to the lung?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 96.","responses":[{"text":"Liver cancer","correct":false,"visible":false},{"text":"Skin cancer","correct":false,"visible":false},{"text":"Prostate cancer","correct":false,"visible":false},{"text":"Breast cancer","correct":true,"visible":false},{"text":"Bone cancer","correct":false,"visible":false}]},{"id":1781,"text":"Which of the following anti-tuberculous drugs is bactericidal?","explanation":null,"reference":"Katzung BG, Kruidering-Hall M, Trevor AJ. Katzung \u0026 Trevor’s Pharmacology Examination \u0026 Board Review. 12th ed. McGraw-Hill Education; 2019: 398.","responses":[{"text":"Ethambutol","correct":false,"visible":false},{"text":"Para amino salicylic acid","correct":false,"visible":false},{"text":"Rifampin","correct":true,"visible":false},{"text":"Cycloserine","correct":false,"visible":false},{"text":"Ethionamide","correct":false,"visible":false}]},{"id":1807,"text":"Which of the following is not associated with chronic obstructive pulmonary disease (COPD)?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 574.","responses":[{"text":"Muscle wasting","correct":false,"visible":false},{"text":"Osteoporosis","correct":false,"visible":false},{"text":"Chronic liver disease","correct":true,"visible":false},{"text":"Depression","correct":false,"visible":false},{"text":"Metabolic syndrome","correct":false,"visible":false}]},{"id":1900,"text":"Regarding laryngeotracheobronchitis, the most frequently observed radiological finding is:","explanation":null,"reference":"Laryngotracheobronchitis - an overview | sciencedirect topics. Accessed May 17, 2022. https://www.sciencedirect.com/topics/pharmacology-toxicology-and-pharmaceutical-science/laryngotracheobronchitis","responses":[{"text":"Ragged tracheal border","correct":false,"visible":false},{"text":"Thumb sign at epiglottis","correct":false,"visible":false},{"text":"Thickened nasopharyngeal space","correct":false,"visible":false},{"text":"Steeple sign","correct":true,"visible":false},{"text":"Normal","correct":false,"visible":false}]},{"id":1921,"text":"The type of asphyxia that is associated with anesthesia and surgical maneuvers is termed as:","explanation":"The type of asphyxia that is associated with anesthesia and surgical maneuvers is termed **iatrogenic asphyxia**. \"Iatrogenic\" refers to conditions or complications that are caused by medical intervention or treatment.\r\n\r\nDuring anesthesia and surgical procedures, there can be various factors that contribute to iatrogenic asphyxia. These may include airway obstruction, inadequate ventilation, or compromised oxygenation due to the effects of anesthesia or surgical manipulation.\r\n\r\nExamples of situations that can lead to iatrogenic asphyxia include the accidental placement of an endotracheal tube in the esophagus instead of the trachea, inadequate oxygen supply during surgery, or complications such as laryngospasm or bronchospasm.\r\n\r\nPrompt recognition and intervention are crucial in managing iatrogenic asphyxia to prevent severe respiratory compromise and potential adverse outcomes.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 161.","responses":[{"text":"Mechanical asphyxia","correct":false,"visible":false},{"text":"Toxic asphyxia","correct":false,"visible":false},{"text":"Iatrogenic asphyxia","correct":true,"visible":false},{"text":"Clinical asphyxia","correct":false,"visible":false},{"text":"Pathological asphyxia","correct":false,"visible":false}]},{"id":2070,"text":"What does the common radiological finding in the case of epiglottitis show?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 140.","responses":[{"text":"X-ray neck AP-view reveals \" steeple sign\"","correct":false,"visible":false},{"text":"Lateral x-ray of neck reveal \"steeple sign\"","correct":false,"visible":false},{"text":"Bilateral nonhomogeneous infiltrations in both lungs with shifting of trachea on right side","correct":false,"visible":false},{"text":"X-ray chest shows bilateral hilar infiltration with shifting of trachea toward left side","correct":false,"visible":false},{"text":"Lateral x-ray of neck reveal \"thumb printing sign\"","correct":true,"visible":false}]},{"id":2372,"text":"What is the cause of death in the peculiar condition termed as 'café coronary'?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 458.","responses":[{"text":"Asphyxia","correct":true,"visible":false},{"text":"Eating in a café","correct":false,"visible":false},{"text":"Fatty meals","correct":false,"visible":false},{"text":"Fish","correct":false,"visible":false},{"text":"Myocardial Infarction","correct":false,"visible":false}]},{"id":2373,"text":"Where is the first sign of internal putrefaction seen?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 148.","responses":[{"text":"Heart","correct":false,"visible":false},{"text":"Bone","correct":false,"visible":false},{"text":"Under surface of the liver","correct":false,"visible":false},{"text":"Kidney","correct":false,"visible":false},{"text":"Spleen","correct":true,"visible":false}]},{"id":2377,"text":"In which of the following disease, FEV1/FVC below 0.7 with an increased total lung capacity, is seen?","explanation":null,"reference":"1) Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 89.\r\n2) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 674.","responses":[{"text":"Sarcoidosis","correct":false,"visible":false},{"text":"Pneumonitis","correct":false,"visible":false},{"text":"Pneumoconiosis","correct":false,"visible":false},{"text":"Restrictive lung disease","correct":false,"visible":false},{"text":"Obstructive lung disease","correct":true,"visible":false}]},{"id":2381,"text":"What is the method of action of montelukast?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 531.","responses":[{"text":"Cytokine receptor anatognist","correct":false,"visible":false},{"text":"Inhibits the cysteinyl leukotriene CysLT1 receptor","correct":true,"visible":false},{"text":"Cytokine receptor agonist","correct":false,"visible":false},{"text":"Leukotriene receptor agonist","correct":false,"visible":false},{"text":"Prevents the release of granules from mast cells","correct":false,"visible":false}]},{"id":2408,"text":"A 55-year-old patient suffering from persistent dry cough for the last 2-months due to unknown reasons wants to get a drug without having constipating effects. Which of the following would you prescribe?","explanation":null,"reference":"Whalen K, Finkel R, Panavelil TA. Lippincott Illustrated Reviews: Pharmacology. 6th ed. Lippincott Williams \u0026 Wilkins; 2015: 390.","responses":[{"text":"Pholcodine","correct":false,"visible":false},{"text":"Codeine","correct":false,"visible":false},{"text":"Dextromethorphan","correct":true,"visible":false},{"text":"Physostigmine","correct":false,"visible":false},{"text":"Hydrocodone","correct":false,"visible":false}]},{"id":2449,"text":"Which of the following is an important microscopical feature of acute respiratory distress syndrome (ARDS)?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 94.","responses":[{"text":"Diffuse septal fibrosis","correct":false,"visible":false},{"text":"Diffuse interstitial fibrosis","correct":false,"visible":false},{"text":"Diffuse alveolar damage","correct":true,"visible":false},{"text":"Diffuse bronchiolar damage","correct":false,"visible":false},{"text":"Diffuse bronchoalveolar damage","correct":false,"visible":false}]},{"id":2456,"text":"What is the maximum volume of air that can be expelled after normal expiration?","explanation":null,"reference":"Inspiratory reserve volume - an overview | sciencedirect topics. Accessed May 17, 2022. https://www.sciencedirect.com/topics/medicine-and-dentistry/inspiratory-reserve-volume","responses":[{"text":"Tidal volume","correct":false,"visible":false},{"text":"Inspiratory reserve volume","correct":false,"visible":false},{"text":"Expiratory reserve volume","correct":true,"visible":false},{"text":"Functional residual capacity","correct":false,"visible":false},{"text":"Residual volume","correct":false,"visible":false}]},{"id":2457,"text":"Which of the following is false about transudative effusion?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 564.","responses":[{"text":"Protein content is \u003c3 g/dL","correct":false,"visible":false},{"text":"Serum LDH ratio is \u003e0.6","correct":true,"visible":false},{"text":"Specific gravity is \u003c1.015","correct":false,"visible":false},{"text":"Occurs mostly in congestive heart failure","correct":false,"visible":false},{"text":"Appearance is colourless","correct":false,"visible":false}]},{"id":2458,"text":"Which of the following is not a feature of transudative pleural effusion?","explanation":null,"reference":"(1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 564. (2) Transudate - an overview | sciencedirect topics. Accessed May 17, 2022. https://www.sciencedirect.com/topics/medicine-and-dentistry/transudate","responses":[{"text":"Pleural fluid to serum LDH ratio \u003c 0.6","correct":false,"visible":false},{"text":"Specific gravity of fluid is less than 1.102","correct":false,"visible":false},{"text":"Pleural fluid to serum protein ratio \u003c 0.5","correct":false,"visible":false},{"text":"Protein content is \u003e 3 g/dl","correct":true,"visible":false},{"text":"Pleural fluid LDH \u003c 2/3 Serum LDH Upper Limit of Normal","correct":false,"visible":false}]},{"id":2540,"text":"What is an interferon-gamma release assay used to diagnose?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 594.","responses":[{"text":"Bacterial pneumonia","correct":false,"visible":false},{"text":"Tuberculosis disease","correct":false,"visible":false},{"text":"Tuberculosis infection","correct":false,"visible":false},{"text":"Latent tuberculosis infection","correct":true,"visible":false},{"text":"Atypical pneumonia","correct":false,"visible":false}]},{"id":2545,"text":"What is the drug of choice for the treatment of bacterial pneumonia?","explanation":null,"reference":"Katzung BG, Kruidering-Hall M, Trevor AJ. Katzung \u0026 Trevor’s Pharmacology Examination \u0026 Board Review. 12th ed. McGraw-Hill Education; 2019: 818.","responses":[{"text":"Aminoglycosides","correct":false,"visible":false},{"text":"Fluoroquinolones","correct":false,"visible":false},{"text":"Penicillins","correct":false,"visible":false},{"text":"Cephalosporins","correct":false,"visible":false},{"text":"Macrolides","correct":true,"visible":false}]},{"id":2546,"text":"What is the most common lung tumor in non-smokers?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 96.","responses":[{"text":"Small cell carcinoma","correct":false,"visible":false},{"text":"Squamous cell carcinoma","correct":false,"visible":false},{"text":"Adenocarcinoma","correct":true,"visible":false},{"text":"Large cell carcinoma","correct":false,"visible":false},{"text":"Carcinoid tumor","correct":false,"visible":false}]},{"id":2547,"text":"Highest p53 mutations are found in which type of lung cancer?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n714.","responses":[{"text":"Squamous cell carcinoma","correct":true,"visible":false},{"text":"Adenocarcinoma","correct":false,"visible":false},{"text":"Small cell cancer","correct":false,"visible":false},{"text":"Large cell carcinoma","correct":false,"visible":false},{"text":"Carcinoma in situ","correct":false,"visible":false}]},{"id":2548,"text":"What causes epithelial damage in asthma?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 91.","responses":[{"text":"Major basic protein","correct":true,"visible":false},{"text":"Eotaxin","correct":false,"visible":false},{"text":"Bradykinin","correct":false,"visible":false},{"text":"Chemokines","correct":false,"visible":false},{"text":"Increased mucus","correct":false,"visible":false}]},{"id":2549,"text":"Which carcinoma secretes antidiuretic hormone and adrenocorticotropic hormone?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 96.","responses":[{"text":"Small cell carcinoma","correct":true,"visible":false},{"text":"Squamous cell carcinoma","correct":false,"visible":false},{"text":"Bronchial carcinoid tumor","correct":false,"visible":false},{"text":"Large cell carcinoma","correct":false,"visible":false},{"text":"Adenocarcinoma","correct":false,"visible":false}]},{"id":2550,"text":"Which of the following is not a characteristic of septic shock?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 70, 71, 196.","responses":[{"text":"Tachycardia","correct":false,"visible":false},{"text":"Respiratory distress","correct":false,"visible":false},{"text":"Alkalosis","correct":true,"visible":false},{"text":"End organ failure","correct":false,"visible":false},{"text":"Hypovolemia","correct":false,"visible":false}]},{"id":2551,"text":"What are the acute effects of poor illumination/lighting?","explanation":null,"reference":"Government of Canada CC for OH and S. Lighting ergonomics - survey and solutions : osh answers. Published May 18, 2022. Accessed May 18, 2022. https://www.ccohs.ca/oshanswers/ergonomics/lighting_survey.html","responses":[{"text":"Minor nystagmus","correct":false,"visible":false},{"text":"Headache and eye pain","correct":true,"visible":false},{"text":"Fatigue","correct":false,"visible":false},{"text":"Blurred vision","correct":false,"visible":false},{"text":"Discomfort","correct":false,"visible":false}]},{"id":2552,"text":"How is an epiglottis infection treated?","explanation":null,"reference":"Epiglottitis infection or inflammation. WebMD. Accessed May 18, 2022. https://www.webmd.com/a-to-z-guides/epiglottitis-infection-inflammation","responses":[{"text":"Oral antibiotics","correct":false,"visible":false},{"text":"Racemic epinephrine","correct":false,"visible":false},{"text":"Intravenous antibiotics","correct":true,"visible":false},{"text":"Antiviral medications","correct":false,"visible":false},{"text":"Mist therapy","correct":false,"visible":false}]},{"id":2582,"text":"Which of the following is not seen in asthma?","explanation":null,"reference":"(1) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 682. (2) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 568, 578.","responses":[{"text":"Bronchial breathing","correct":true,"visible":false},{"text":"Episodic dyspnea","correct":false,"visible":false},{"text":"Nocturnal cough","correct":false,"visible":false},{"text":"Tachycardia","correct":false,"visible":false},{"text":"Wheezing","correct":false,"visible":false}]},{"id":2583,"text":"Which of the following is true about rigor mortis?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 141.","responses":[{"text":"It is also called instantaneous rigor","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"It is the stiffening of body muscles after death","correct":true,"visible":false},{"text":"It is called false mortis","correct":false,"visible":false},{"text":"It occurs 48 hours after death","correct":false,"visible":false}]},{"id":2589,"text":"Which of the following is a characteristic of small cell carcinoma of the lung?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015:  717.","responses":[{"text":"Lepidic growth pattern of tall columnar cells","correct":false,"visible":false},{"text":"Lepidic growth pattern of cuboidal cells","correct":false,"visible":false},{"text":"Undifferentiated malignant epithelial tumor","correct":false,"visible":false},{"text":"Keratin pearls and intercellular bridges","correct":false,"visible":false},{"text":"Round or oval cells with scant cytoplasm and nuclear molding (salt and pepper appearance)","correct":true,"visible":false}]},{"id":2599,"text":"Which of the following is not associated with diffuse parenchymal lung diseases?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n686.","responses":[{"text":"Dry cough","correct":false,"visible":false},{"text":"Productive cough","correct":true,"visible":false},{"text":"Shortness of breath","correct":false,"visible":false},{"text":"Joint pain","correct":false,"visible":false},{"text":"Clubbing","correct":false,"visible":false}]},{"id":2600,"text":"Which of the following is used to determine ventilation abnormalities?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 569.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Total lung capacity","correct":false,"visible":false},{"text":"Residual volume","correct":false,"visible":false},{"text":"Functional residual capacity","correct":false,"visible":false},{"text":"Forced expiratory volume","correct":true,"visible":false}]},{"id":2606,"text":"Asbestosis is not associated with which of the following?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 93.","responses":[{"text":"Bronchial asthma","correct":true,"visible":false},{"text":"Pleural plaques","correct":false,"visible":false},{"text":"Mesothelioma","correct":false,"visible":false},{"text":"Interstitial fibrosis","correct":false,"visible":false},{"text":"Lung cancer","correct":false,"visible":false}]},{"id":2609,"text":"A coal mine worker develops chest pain which decreases their ability to work. What is the most likely diagnosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 93.","responses":[{"text":"Siderosis","correct":false,"visible":false},{"text":"Asbestosis","correct":false,"visible":false},{"text":"Farmer's lung","correct":false,"visible":false},{"text":"Coal workers' pneumoconiosis","correct":true,"visible":false},{"text":"Silicosis","correct":false,"visible":false}]},{"id":2610,"text":"What is the best indicator of air pollution?","explanation":null,"reference":"Common air pollution indicators and their use in economic studies. Knowledge Tank. Published July 16, 2018. Accessed May 18, 2022. https://www.projectguru.in/common-air-pollution-indicators-economic-studies/","responses":[{"text":"Carbon monoxide","correct":false,"visible":false},{"text":"Methane","correct":false,"visible":false},{"text":"Smoke, suspended particles and sulfur dioxide","correct":false,"visible":false},{"text":"Sulphur dioxide","correct":false,"visible":false},{"text":"Particulate matter","correct":true,"visible":false}]},{"id":2615,"text":"Which of the following is not a complication of pneumonia?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 585.","responses":[{"text":"Lung abscess","correct":false,"visible":false},{"text":"Pleuritis","correct":false,"visible":false},{"text":"Pleural effusion","correct":false,"visible":false},{"text":"Bronchogenic carcinoma","correct":true,"visible":false},{"text":"Empyema","correct":false,"visible":false}]},{"id":2629,"text":"What is meant by ergonomics?","explanation":null,"reference":"(1) Park K. Park’s Textbook of Preventive and Social Medicine. 25th ed.; 2019: 864. (2) Ilyas M. Public Health and Community Medicine. 8th ed. TIME Publisher; 2016: 752.","responses":[{"text":"Fitting the worker to the job","correct":false,"visible":false},{"text":"Fitting the job to the surroundings","correct":false,"visible":false},{"text":"Fitting worker to the surroundings","correct":false,"visible":false},{"text":"Fitting the surroundings to the worker","correct":false,"visible":false},{"text":"Fitting the job to the worker","correct":true,"visible":false}]},{"id":2630,"text":"Which of the below enlisted is the most significant occupational hazard from long-term ionizing radiation exposure?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n325.","responses":[{"text":"Hair loss","correct":false,"visible":false},{"text":"Decreased sperm","correct":false,"visible":false},{"text":"Flushed skin","correct":false,"visible":false},{"text":"Genetic changes","correct":true,"visible":false},{"text":"Decreased libido","correct":false,"visible":false}]},{"id":2631,"text":"What occupational hazard is associated with welding?","explanation":null,"reference":"Government of Canada CC for OH and S. Welding - radiation and the effects on eyes and skin : osh answers. Published May 18, 2022. Accessed May 18, 2022. https://www.ccohs.ca/oshanswers/safety_haz/welding/eyes.html","responses":[{"text":"Conjuctivitis","correct":true,"visible":false},{"text":"Gingivitis","correct":false,"visible":false},{"text":"Pleuritis","correct":false,"visible":false},{"text":"Carditis","correct":false,"visible":false},{"text":"Orchitis","correct":false,"visible":false}]},{"id":2633,"text":"What is the most common cause of bacterial pneumonia in children?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 88.","responses":[{"text":"Haemophilus influenzae","correct":false,"visible":false},{"text":"Klebsiella pneumoniae","correct":false,"visible":false},{"text":"Staphylococcus aureus","correct":false,"visible":false},{"text":"Streptococcus pneumoniae","correct":true,"visible":false},{"text":"Legionella","correct":false,"visible":false}]},{"id":2634,"text":"What is the pathology of bronchiectasis?","explanation":null,"reference":"(1)Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 699.\r\n(2) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 683","responses":[{"text":"Chronic pyogenic infections","correct":false,"visible":false},{"text":"Type I hypersensitivity","correct":false,"visible":false},{"text":"Increased ciliary movement","correct":false,"visible":false},{"text":"Chronic necrotizing infections","correct":true,"visible":false},{"text":"Acute necrotizing infections","correct":false,"visible":false}]},{"id":2635,"text":"When is a gastric lavage contraindicated?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 474.","responses":[{"text":"Aspirin overdose","correct":false,"visible":false},{"text":"Carbolic acid poisioning","correct":false,"visible":false},{"text":"Iron tablet overdose","correct":false,"visible":false},{"text":"Blood meal","correct":false,"visible":false},{"text":"Corrosive poisoning","correct":true,"visible":false}]},{"id":2636,"text":"What can a saddle embolus lead to?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 39.","responses":[{"text":"Pulmonary hypertension","correct":false,"visible":false},{"text":"Sudden death","correct":true,"visible":false},{"text":"Nose bleed","correct":false,"visible":false},{"text":"Hemorrhage","correct":false,"visible":false},{"text":"Chest pain","correct":false,"visible":false}]},{"id":2637,"text":"What is Mikulicz syndrome characterized by?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 227.","responses":[{"text":"Abnormal enlargement of glands in the thorax","correct":false,"visible":false},{"text":"Abnormal enlargement of glands in the limbs","correct":false,"visible":false},{"text":"Abnormal enlargement of glands in the pelvis","correct":false,"visible":false},{"text":"Abnormal enlargement of glands in the perineum","correct":false,"visible":false},{"text":"Abnormal enlargement of glands in the head and neck","correct":true,"visible":false}]},{"id":2638,"text":"What is centriacinar emphysema caused by?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 90.","responses":[{"text":"Smoking","correct":true,"visible":false},{"text":"Radiation","correct":false,"visible":false},{"text":"Wool","correct":false,"visible":false},{"text":"Asbestos","correct":false,"visible":false},{"text":"Beryllium","correct":false,"visible":false}]},{"id":2664,"text":"ICU admission for a patient with pneumonia is indicated with which CURB-65 score?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 583.","responses":[{"text":"3","correct":false,"visible":false},{"text":"3 or more","correct":true,"visible":false},{"text":"2","correct":false,"visible":false},{"text":"1","correct":false,"visible":false},{"text":"4 or more","correct":false,"visible":false}]},{"id":2667,"text":"What level of the respiratory tract is choking seen at?","explanation":null,"reference":"D'24 lecture slides: Respiratory module, forensic-medicine lecture slides, Topic: Asphyxia I, Sub-topic: Mechanical/Violent Asphyxial Deaths.","responses":[{"text":"Nose and mouth","correct":false,"visible":false},{"text":"Main bronchus","correct":false,"visible":false},{"text":"Trachea","correct":false,"visible":false},{"text":"Glottis","correct":true,"visible":false},{"text":"Larynx","correct":false,"visible":false}]},{"id":2670,"text":"Which of the following arteries is most commonly blocked in autopsy in case of coronary atherosclerosis?","explanation":"The most commonly blocked artery in cases of coronary atherosclerosis is the **left anterior descending artery (LAD)**. The LAD supplies a large portion of the left ventricle, including the anterior wall, septum, and apex of the heart. It is a major branch of the left coronary artery and is susceptible to plaque buildup and narrowing, leading to reduced blood flow and potentially causing a heart attack.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 132.","responses":[{"text":"Circumflex artery","correct":false,"visible":false},{"text":"Right marginal artery","correct":false,"visible":false},{"text":"Left subclavian artery","correct":false,"visible":false},{"text":"Right coronary artery","correct":false,"visible":false},{"text":"Left anterior descending artery","correct":true,"visible":false}]},{"id":2682,"text":"Which is the most common lung cancer seen in women?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 96.","responses":[{"text":"Large cell carcinoma","correct":false,"visible":false},{"text":"Small cell carcinoma","correct":false,"visible":false},{"text":"Bronchioalveolar carcinoma","correct":false,"visible":false},{"text":"Adenocarcinoma","correct":true,"visible":false},{"text":"Squamous cell carcinoma","correct":false,"visible":false}]},{"id":2696,"text":"A 50-year-old male works at a coal mine for the past 7 years. He is also a  smoker. He presents with complaints of progressive dyspnea and pulmonary hypertension. His biopsy shows extensive carbon-laden macrophages with extensive fibrosis. What is the most likely diagnosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 93.","responses":[{"text":"Coal workers' pneumoconiosis","correct":true,"visible":false},{"text":"Silicosis","correct":false,"visible":false},{"text":"Farmer's lung","correct":false,"visible":false},{"text":"Siderosis","correct":false,"visible":false},{"text":"Asthma","correct":false,"visible":false}]},{"id":2701,"text":"A 2-year-old boy is brought to the clinic with a barking cough and hoarseness of voice. What is the most likely diagnosis?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 167.","responses":[{"text":"Acute pharyngitis","correct":false,"visible":false},{"text":"Acute epiglottitis","correct":false,"visible":false},{"text":"Tonsillitis","correct":false,"visible":false},{"text":"Pneumonia","correct":false,"visible":false},{"text":"Acute laryngotracheitis","correct":true,"visible":false}]},{"id":2702,"text":"Which of the following are complications of asbestosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 93.","responses":[{"text":"Cardiac arrhythmias","correct":false,"visible":false},{"text":"Pneumonia","correct":false,"visible":false},{"text":"Congestive heart failure","correct":false,"visible":false},{"text":"Pleural and lung cancers","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":2709,"text":"Which of the following is a complication of silicosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 93.","responses":[{"text":"Pulmonary embolism","correct":false,"visible":false},{"text":"Tuberculosis","correct":true,"visible":false},{"text":"Pulmonary hypertension","correct":false,"visible":false},{"text":"Coughing","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":2711,"text":"Which of these is not a risk factor for tuberculosis in children?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 589.","responses":[{"text":"Close contact with affected person","correct":false,"visible":false},{"text":"Enclosed, poorly ventilated spaces","correct":false,"visible":false},{"text":"Positive skin test","correct":false,"visible":false},{"text":"Cardiac problems","correct":true,"visible":false},{"text":"Malignancy","correct":false,"visible":false}]},{"id":2712,"text":"Which of the following is true about terbutaline?","explanation":null,"reference":"Katzung BG, Kruidering-Hall M, Trevor AJ. Katzung \u0026 Trevor’s Pharmacology Examination \u0026 Board Review. 12th ed. McGraw-Hill Education; 2019: 174.","responses":[{"text":"It is a vasoconstrictor","correct":false,"visible":false},{"text":"It is a beta-2 antagonist","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"It is a bronchodilator","correct":true,"visible":false},{"text":"All of these","correct":false,"visible":false}]},{"id":2713,"text":"Which of the following investigations are done to confirm tuberculosis?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 591, 592.","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Purified protein derivative skin test","correct":false,"visible":false},{"text":"Lung biopsy","correct":false,"visible":false},{"text":"3 morning sputum samples taken for sputum culture","correct":true,"visible":false},{"text":"Sputum staining","correct":false,"visible":false}]},{"id":2714,"text":"Which of the following is a differentiating point between chronic obstructive pulmonary disease (COPD) and asthma?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 569.","responses":[{"text":"Bronchodilator reversibility \u003e15% in COPD","correct":false,"visible":false},{"text":"Asthma is a restrictive lung disease","correct":false,"visible":false},{"text":"Bronchodilator reversibility \u003e15% in asthma","correct":true,"visible":false},{"text":"Allergic rhinitis is a feature of asthma","correct":false,"visible":false},{"text":"Diurnal variation is present in COPD","correct":false,"visible":false}]},{"id":2715,"text":"What is the best first-line diagnostic test for pulmonary embolism?","explanation":"The best first-line diagnostic test for pulmonary embolism is **computerized tomography (CT) pulmonary angiography**.\r\n\r\nPulmonary embolism (PE) occurs when a blood clot (thrombus) travels to the lungs and obstructs the pulmonary arteries. CT pulmonary angiography is the preferred initial diagnostic test for suspected PE due to its high sensitivity and specificity. It involves the injection of a contrast dye into a vein, followed by CT scanning of the pulmonary arteries. This imaging technique allows for the visualization of the blood vessels in the lungs and can identify the presence of a clot.\r\n\r\nOther diagnostic tests mentioned, such as chest x-ray, arterial blood gases, coagulation profile, and electrocardiography, may provide supportive information but are not considered first-line tests for confirming or ruling out pulmonary embolism. Chest x-ray may show nonspecific findings, while arterial blood gases and electrocardiography can indicate secondary changes due to compromised lung function. Coagulation profile may help evaluate the patient's overall coagulation status but is not specific to pulmonary embolism.","reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 620.","responses":[{"text":"Arterial blood gases","correct":false,"visible":false},{"text":"Electrocardiography","correct":false,"visible":false},{"text":"Computerized tomography (CT) pulmonary angiography","correct":true,"visible":false},{"text":"Chest x-ray","correct":false,"visible":false},{"text":"Coagulation profile","correct":false,"visible":false}]},{"id":2716,"text":"Which of the following is the mechanism of action of methylxanthines?","explanation":null,"reference":"Katzung BG, Kruidering-Hall M, Trevor AJ. Katzung \u0026 Trevor’s Pharmacology Examination \u0026 Board Review. 12th ed. McGraw-Hill Education; 2019: 175.","responses":[{"text":"Decrease in cAMP","correct":false,"visible":false},{"text":"Inhibition of phosphodiesterase","correct":true,"visible":false},{"text":"Inhibition of phospholipase C","correct":false,"visible":false},{"text":"Decrease in cGMP","correct":false,"visible":false},{"text":"Activation of adenosine receptors","correct":false,"visible":false}]},{"id":2746,"text":"What is red hepatization caused by?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n704.","responses":[{"text":"Enzymatic digestion of exudate by macrophages","correct":false,"visible":false},{"text":"Exudate with fibrin, white blood cells, and lysed red blood cells","correct":false,"visible":false},{"text":"Exudate with fibrin, bacteria, red blood cells, and white blood cells","correct":true,"visible":false},{"text":"Transudate with fibrin, bacteria, and red blood cells","correct":false,"visible":false},{"text":"Exudate with mostly bacteria","correct":false,"visible":false}]},{"id":2748,"text":"After the exhumation of a body, the gender is determined from which of the following bones?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 64.","responses":[{"text":"Fingers","correct":false,"visible":false},{"text":"Ribs","correct":false,"visible":false},{"text":"Pelvis","correct":true,"visible":false},{"text":"Femur","correct":false,"visible":false},{"text":"Skull","correct":false,"visible":false}]},{"id":2749,"text":"A woman is hypoglycemic and shows some respiratory signs. Upon investigation, she has a tumor that is attached to the pleura with a pedicle. What is the most likely condition?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 723.","responses":[{"text":"Solitary fibrous tumor","correct":true,"visible":false},{"text":"Histoplasmosis","correct":false,"visible":false},{"text":"Metastasis","correct":false,"visible":false},{"text":"Mesothelioma","correct":false,"visible":false},{"text":"Sociable fibrous tumor","correct":false,"visible":false}]},{"id":2750,"text":"Which of the following methods is used to make a diagnosis of sarcoidosis?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 610.","responses":[{"text":"Gastric lavage","correct":false,"visible":false},{"text":"Sputum culture","correct":false,"visible":false},{"text":"Bronchoalveolar lavage","correct":false,"visible":false},{"text":"Transbronchial biopsy","correct":true,"visible":false},{"text":"Chest x-ray","correct":false,"visible":false}]},{"id":2751,"text":"What type of antidote prevents the absorption of poison?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 475.","responses":[{"text":"Physiologic","correct":false,"visible":false},{"text":"Mechanical","correct":true,"visible":false},{"text":"Chemical","correct":false,"visible":false},{"text":"Universal","correct":false,"visible":false},{"text":"Biological","correct":false,"visible":false}]},{"id":2752,"text":"Which interleukin is responsible for eosinophilia in asthma?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 680.","responses":[{"text":"IL-4","correct":false,"visible":false},{"text":"IL-5","correct":true,"visible":false},{"text":"IL-10","correct":false,"visible":false},{"text":"IL-1","correct":false,"visible":false},{"text":"IL-8","correct":false,"visible":false}]},{"id":2764,"text":"What leads to icterus?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n118.","responses":[{"text":"Bilirubin deposition in the sclera","correct":true,"visible":false},{"text":"Bilirubin deposition in the ears","correct":false,"visible":false},{"text":"Bilirubin deposition in the skin","correct":false,"visible":false},{"text":"Bilirubin deposition in the stomach","correct":false,"visible":false},{"text":"Bilirubin deposition in the heart","correct":false,"visible":false}]},{"id":2765,"text":"Which of the following is the best indicator for a shock?","explanation":null,"reference":"Uptodate. Accessed May 20, 2022. https://www.uptodate.com/contents/evaluation-of-and-initial-approach-to-the-adult-patient-with-undifferentiated-hypotension-and-shock","responses":[{"text":"Seizures","correct":false,"visible":false},{"text":"Bradycardia","correct":false,"visible":false},{"text":"Fever","correct":false,"visible":false},{"text":"Tachycardia","correct":false,"visible":false},{"text":"Hypotension","correct":true,"visible":false}]},{"id":2766,"text":"Which organs are affected by sarcoidosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 93.","responses":[{"text":"Spleen","correct":false,"visible":false},{"text":"All of them","correct":true,"visible":false},{"text":"Liver","correct":false,"visible":false},{"text":"Lungs","correct":false,"visible":false},{"text":"Kidneys","correct":false,"visible":false}]},{"id":2767,"text":"What is the most common preservative used for the preservation of viscera?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 114.","responses":[{"text":"Bicarbonate","correct":false,"visible":false},{"text":"Sodium chloride","correct":true,"visible":false},{"text":"Potassium chloride","correct":false,"visible":false},{"text":"Dihydrogen monoxide","correct":false,"visible":false},{"text":"Sulfuric acid","correct":false,"visible":false}]},{"id":2768,"text":"What is the mechanism of action of corticosteroids?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 354-355.","responses":[{"text":"Inhibition of inflammatory eosinophils","correct":false,"visible":false},{"text":"Inhibition of inflammatory macrophages","correct":false,"visible":false},{"text":"Inhibition of inflammatory cytokines","correct":true,"visible":false},{"text":"Inhibition of inflammatory neutrophils","correct":false,"visible":false},{"text":"Attenuation of inflammatory cytokines","correct":false,"visible":false}]},{"id":2769,"text":"A diver has a condition that arises from dissolved gases coming out of solution into bubbles upon depressurization of the body. What is this condition known as?","explanation":null,"reference":"(1) Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 38. (2) Phatak UA, David EJ, Kulkarni PM. Decompression syndrome (Caisson disease) in an Indian diver. Annals of Indian Academy of Neurology. Published 2010. Accessed May 19, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC2981759","responses":[{"text":"Drowning","correct":false,"visible":false},{"text":"Cow's disease","correct":false,"visible":false},{"text":"Diving disease","correct":false,"visible":false},{"text":"Caisson disease","correct":true,"visible":false},{"text":"Carrion disease","correct":false,"visible":false}]},{"id":2780,"text":"Which of the following is not associated with paraneoplastic syndrome?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1230, 1316.","responses":[{"text":"Subacute sensory neuropathy","correct":false,"visible":false},{"text":"Cerebellar degeneration","correct":false,"visible":false},{"text":"Lambert-Eaton syndrome","correct":false,"visible":false},{"text":"Guillain-Barre syndrome","correct":true,"visible":false},{"text":"Stiff-man syndrome","correct":false,"visible":false}]},{"id":2790,"text":"Which of the following is an example of a negative autopsy?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 116.","responses":[{"text":"Vascular rejection of cardiac allograft","correct":false,"visible":false},{"text":"Asphyxia","correct":false,"visible":false},{"text":"Vagal inhibition","correct":true,"visible":false},{"text":"Penetrating fragment injuries in explosion","correct":false,"visible":false},{"text":"Pulmonary embolism","correct":false,"visible":false}]},{"id":2791,"text":"Which of the following organisms is responsible for putrefaction?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 147.","responses":[{"text":"Pseudomonas","correct":false,"visible":false},{"text":"Clostridium welchii","correct":true,"visible":false},{"text":"Listeria monocytogenes","correct":false,"visible":false},{"text":"Spirochaetes","correct":false,"visible":false},{"text":"Chlamydiae","correct":false,"visible":false}]},{"id":2796,"text":"What is the first external sign of putrefaction?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 147.","responses":[{"text":"Distension","correct":false,"visible":false},{"text":"Postmortem luminescence","correct":false,"visible":false},{"text":"Marbling of skin","correct":false,"visible":false},{"text":"Greenish discoloration over the right iliac fossa","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":2797,"text":"Which of the following is a long-acting beta-agonist?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 712.","responses":[{"text":"Metaproterenol","correct":false,"visible":false},{"text":"Tiotropium","correct":false,"visible":false},{"text":"Albuterol","correct":false,"visible":false},{"text":"Salmeterol","correct":true,"visible":false},{"text":"Ipratropium","correct":false,"visible":false}]},{"id":2798,"text":"Which of the following is a rare site of lung cancer metastasis?","explanation":null,"reference":"Milovanovic IS, Stjepanovic M, Mitrovic D. Distribution patterns of the metastases of the lung carcinoma in relation to histological type of the primary tumor: An autopsy study. Annals of Thoracic Medicine. Published 2017. Accessed May 20, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC5541967/","responses":[{"text":"Kidney","correct":true,"visible":false},{"text":"Liver","correct":false,"visible":false},{"text":"Brain","correct":false,"visible":false},{"text":"Adrenal glands","correct":false,"visible":false},{"text":"Bone","correct":false,"visible":false}]},{"id":2799,"text":"Which of the following is the best X-ray view for pneumothorax?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 551.","responses":[{"text":"Lateral","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"All of these","correct":false,"visible":false},{"text":"Posteroanterior","correct":true,"visible":false},{"text":"Anteroposterior","correct":false,"visible":false}]}
]

